            else:
                chain_active = False  # No more matches, chain ends
                self.chain_multiplier = 1.0  # Reset multiplier for the next piece

        return total_score # accumulated score

    def process_grid(self):
        matches = self.detect_matches()
        if matches:
            self.chain_reaction = True
